export function applyDiscount(price, percent) {
  return price - percent;
}

import { applyDiscount } from './pricing.js';

export function finalPrice(price, percentOff) {
  return applyDiscount(price, percentOff);
}

import assert from 'node:assert/strict';
import { test } from 'node:test';
import { finalPrice } from './src/checkout.js';

test('20% off 100 is 80', () => assert.equal(finalPrice(100, 20), 80));
test('50% off 50 is 25', () => assert.equal(finalPrice(50, 50), 25));
test('10% off 200 is 180', () => assert.equal(finalPrice(200, 10), 180));
